        google: { rating: 4.2, review_count: 31, maps_url: 'https://maps.google.com/?cid=17364636064590845062&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA', reviews: [{author: 'Justin Blair', rating: 5, text: 'Z had my back! I accidentally left my wallet at this store right at closing time while visiting from out of town. Z immediately answered my call after hours, found it, and went out of his way to make sure it was safely returned. I thought I was in big trouble but I seriously appreciate the honesty and customer care. I highly recommend this place for both their products and their integrity. Thank y', time: '5 months ago'}, {author: 'Matthew Bayer', rating: 5, text: 'Besides the merch, the people here have always been amazing! They are quick to talk and give you assistance if needed. But they will also just let you shop around if you prefer that. Always have a good sale and deals. Great place for a small town!', time: '11 months ago'}, {author: 'Lizzie Villanueva', rating: 5, text: 'Super cute shop! The owner has a really good eye and does a great job at creating a unique and fun space for each of his stores. A variety of products to choose from- even for your furry friends. Staff is very personable and takes their time to get to know you- I always leave having had a friendly interaction and positive experience. And bonus points for being dog friendly!', time: 'a year ago'}, {author: 'Douglas Adams', rating: 1, text: 'They need to post that this is not a recreational dispensary! Edibles drinks of hemp! Yuck!', time: '2 months ago'}, {author: 'Anonymous', rating: 5, text: 'First time stopping in today. Had the drinks I wanted! Simple but they will build up stock. Comfortable atmosphere. Cannot wait to go again and see the new stock.', time: 'a year ago'}] }
