        google: { rating: 4.7, review_count: 46, maps_url: 'https://maps.google.com/?cid=10576233472941968014&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA', reviews: [{author: 'Daniel Christian', rating: 5, text: 'Very cool little shop. Lots of varieties of merchandise and the staff are all super friendly and helpful with whatever you need. Definitely worth stopping by and giving them a look!', time: '3 weeks ago'}, {author: 'Nick Giusti', rating: 5, text: 'This boutique is an amazing hidden gem north of the Twin Cities. They have a large assortment of unique items that you can\'t find anywhere else. It truly has something for everyone. You will not leave empty handed. If you\'re looking for a special one of a kind gift for a loved one this is your spot. The staff is very welcoming, friendly, and knowledgeable. Highly recommend.', time: 'a year ago'}, {author: 'Alicia Dziubak', rating: 5, text: 'This is such a cute little store with a variety of items for all ages and for 21+. The shop is very welcoming and inviting from the time you enter to the time you leave. It smells great as well and is so clean/organized. The owners are very knowledgeable and they will help with making decisions on the 21+ products (drinks, vapes, gummies, etc...) to be sure you get what you want and are pleased! T', time: 'a year ago'}, {author: 'Christina Smith', rating: 5, text: 'Such a great shop! They have something for everyone . Such a eclectic selection. The owners and staff are very friendly and knowledgeable. Truly such a beautiful place! I definitely will be back.', time: 'a year ago'}, {author: 'Jacob Miller', rating: 5, text: 'Cute little health and wellness shop. Lots of gems. From crystals, clothing, bath salts and edibles. I love the Doctor Dabs Maple Sodas!! The OnPoint Cookies and Cream bars are delicious as well. The owners were very knowledgeable and helped me find great products for me to try.', time: 'a year ago'}] }
