        google: { rating: 4.7, review_count: 490, maps_url: 'https://maps.google.com/?cid=12002727602885414247&g_mp=CiVnb29nbGUubWFwcy5wbGFjZXMudjEuUGxhY2VzLkdldFBsYWNlEAIYBCAA', reviews: [{author: 'Dave C', rating: 5, text: 'Fast and friendly! I was expertly guided through the medical cannabis process by Tessa. She was knowledgeable about the product and shared her experience with the cannabis and how she got good pain relief. She was correct in her assessment as I experienced the same relief. Awesome staff and great customer service. Thank you, Tessa!', time: 'a month ago'}, {author: 'Miranda Gunderson', rating: 5, text: 'I always have a great experience at the Willmar location. The staff members are always friendly and welcoming. The vibe is great and the product is as well! Tessa was very helpful in my visit today.', time: '4 months ago'}, {author: 'Makayla Willprecht', rating: 5, text: 'Had such a great experience at Rise Dispensary in Willmar! The staff was super welcoming, knowledgeable, and made everything feel easy and comfortable. Ask for Emma! she helped me out and was absolutely amazing—patient, friendly, and really took the time to explain options and answer questions without any pressure. You can tell she genuinely cares about people and what she does. Clean space, good ', time: '2 months ago'}, {author: 'Krista Ritzer', rating: 5, text: 'The staff here is amazing! They are so knowledgeable and welcoming. I used my med card and got some yummy edibles. Beboe is my favorite!!', time: '2 months ago'}, {author: 'Edwin Ortega', rating: 5, text: 'First timer at the Willmar location and they got me in and out real quick. The crew member Tessa was very friendly and informative, she went a step further and made sure I was aware of the amount of points I had so I don’t forget on my next visit. Overall great location!', time: '2 months ago'}] }
